	Let $p \geq 2$ be an integer and let $\mathbf{C}_0$ be as in Assumption \ref{ass:cone} with $q=0$. There are constants $C$, $\eta>0$, and $\rho > 0$, depending only on $m,n,p$, and $\mathbf{C}_0$ with the following property. Assume that $\Sigma$ and $T$ are as in the Assumption \ref{assumption:manifolds and currents} with $R_0=1$, that $\hat\mathscr{F}^p_{\mathbf{B}_1}(T-\mathbf{C}_0) \leq \eta$ and that $\mathbf{C}$ is a representative ${\rm mod}(p)$ cycle (not necessarily area-minimizing), with the following properties:
	\begin{itemize}
	\item[(i)] $\mathbf{C}$ is a cone coherent with $\mathbf{C}_0$ and $\vartheta (\mathbf{C}, \mathbf{C}_0) \leq \eta$;
	\item[(ii)] $\max\{ \mathbf{E} (T,\mathrm{spt} (\mathbf{C}), 0, 1), \mathbf{A}^{\sfrac 12}\}\leq \eta$.
	\end{itemize}
	Then there is a representative ${\rm mod}(p)$ cycle $\mathbf{C}'$ which is a cone coherent with $\mathbf{C}_0$ and satisfies the following estimates:
	\begin{align}
	&\max \{\mathbf{E}(T, \mathrm{spt}(\mathbf{C}'), 0, \rho), (\rho \mathbf{A})^{\sfrac 12}\} \leq \rho^{1/2} \max\{\mathbf{E}(T,\mathrm{spt}(\mathbf{C}), 0, 1),\mathbf{A}^{\sfrac 12}\}\, , \label{e:decay}\\
	&\hat\mathscr{F}^p_{\mathbf{B}_1} ((\eta_{0, \rho})_\sharp T-\mathbf{C}') \leq C (\mathbf{E}(T,\mathrm{spt}(\mathbf{C}), 0, 1) + \mathbf{A})^{\sfrac 12}\, ,\label{e:flat-C'}\\
	&\vartheta (\mathbf{C}', \mathbf{C}_0) \leq \vartheta (\mathbf{C}, \mathbf{C}_0) + C (\mathbf{E}(T,\mathrm{spt}(\mathbf{C}), 0, 1) + \mathbf{A})^{\sfrac 12}\, .\label{e:incremento-angolo}
	\end{align}

